199: void ActiveStreamFilterBase::commonHandleBufferData(Buffer::Instance& provided_data) {
200: 
201:   // The way we do buffering is a little complicated which is why we have this common function
202:   // which is used for both encoding and decoding. When data first comes into our filter pipeline,
203:   // we send it through. Any filter can choose to stop iteration and buffer or not. If we then
204:   // continue iteration in the future, we use the buffered data. A future filter can stop and
205:   // buffer again. In this case, since we are already operating on buffered data, we don't
206:   // rebuffer, because we assume the filter has modified the buffer as it wishes in place.
207:   if (bufferedData().get() != &provided_data) {
208:     if (!bufferedData()) {
209:       bufferedData() = createBuffer();
210:     }
211:     bufferedData()->move(provided_data);
212:   }
213: }
