250: bool ActiveStreamFilterBase::commonHandleAfterTrailersCallback(FilterTrailersStatus status) {
251: 
252:   if (status == FilterTrailersStatus::Continue) {
253:     if (iteration_state_ == IterationState::StopSingleIteration) {
254:       commonContinue();
255:       return false;
256:     } else {
257:       ASSERT(headers_continued_);
