574: void ConnectionManagerImpl::resetAllStreams(
575:     absl::optional<StreamInfo::CoreResponseFlag> response_flag, absl::string_view details) {
576:   while (!streams_.empty()) {
577:     // Mimic a downstream reset in this case. We must also remove callbacks here. Though we are
578:     // about to close the connection and will disable further reads, it is possible that flushing
579:     // data out can cause stream callbacks to fire (e.g., low watermark callbacks).
580:     //
581:     // TODO(mattklein123): I tried to actually reset through the codec here, but ran into issues
582:     // with nghttp2 state and being unhappy about sending reset frames after the connection had
583:     // been terminated via GOAWAY. It might be possible to do something better here inside the h2
584:     // codec but there are no easy answers and this seems simpler.
585:     auto& stream = *streams_.front();
586:     stream.response_encoder_->getStream().removeCallbacks(stream);
587:     if (!stream.response_encoder_->getStream().responseDetails().empty()) {
588:       stream.filter_manager_.streamInfo().setResponseCodeDetails(
589:           stream.response_encoder_->getStream().responseDetails());
590:     } else if (!details.empty()) {
591:       stream.filter_manager_.streamInfo().setResponseCodeDetails(details);
592:     }
593:     if (response_flag.has_value()) {
594:       stream.filter_manager_.streamInfo().setResponseFlag(response_flag.value());
595:     }
596:     stream.onResetStream(StreamResetReason::ConnectionTermination, absl::string_view());
597:   }
598: }
