690:   StreamDecoderFilters::Iterator entry = commonDecodePrefix(filter, filter_iteration_start_state);
691:   bool terminal_filter_decoded_end_stream = false;
692:   ASSERT(!state_.decoder_filter_chain_complete_ || entry == decoder_filters_.end() ||
693:          (*entry)->end_stream_);
