695:   for (; entry != decoder_filters_.end(); entry++) {
696:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
697:     // If the filter pointed by entry has stopped for all frame types, return now.
698:     if (handleDataIfStopAll(**entry, data, state_.decoder_filters_streaming_)) {
