702:     //
703:     // In following case, ActiveStreamFilterBase::commonContinue() could be called recursively and
704:     // its doData() is called with wrong data.
705:     //
706:     //  There are 3 decode filters and "wrapper" refers to ActiveStreamFilter object.
707:     //
708:     //  filter0->decodeHeaders(_, true)
709:     //    return STOP
710:     //  filter0->continueDecoding()
711:     //    wrapper0->commonContinue()
712:     //      wrapper0->decodeHeaders(_, _, true)
713:     //        filter1->decodeHeaders(_, true)
714:     //          filter1->addDecodeData()
715:     //          return CONTINUE
716:     //        filter2->decodeHeaders(_, false)
717:     //          return CONTINUE
718:     //        wrapper1->commonContinue() // Detects data is added.
719:     //          wrapper1->doData()
720:     //            wrapper1->decodeData()
721:     //              filter2->decodeData(_, true)
722:     //                 return CONTINUE
723:     //      wrapper0->doData() // This should not be called
724:     //        wrapper0->decodeData()
725:     //          filter1->decodeData(_, true)  // It will cause assertions.
726:     //
727:     // One way to solve this problem is to mark end_stream_ for each filter.
728:     // If a filter is already marked as end_stream_ when decodeData() is called, bails out the
729:     // whole function. If just skip the filter, the codes after the loop will be called with
730:     // wrong data. For encodeData, the response_encoder->encode() will be called.
731:     if ((*entry)->end_stream_) {
732:       return;
733:     }
734:     ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeData));
735: 
736:     // We check the request_trailers_ pointer here in case addDecodedTrailers
737:     // is called in decodeData during a previous filter invocation, at which point we communicate to
738:     // the current and future filters that the stream has not yet ended.
739:     if (end_stream) {
740:       state_.filter_call_state_ |= FilterCallState::EndOfStream;
741:     }
742: 
743:     recordLatestDataFilter(entry, state_.latest_data_decoding_filter_, decoder_filters_);
744: 
745:     state_.filter_call_state_ |= FilterCallState::DecodeData;
746:     (*entry)->end_stream_ = end_stream && !filter_manager_callbacks_.requestTrailers();
747:     FilterDataStatus status = (*entry)->handle_->decodeData(data, (*entry)->end_stream_);
748:     if ((*entry)->end_stream_) {
749:       (*entry)->handle_->decodeComplete();
750:     }
751:     state_.filter_call_state_ &= ~FilterCallState::DecodeData;
752:     if (end_stream) {
753:       state_.filter_call_state_ &= ~FilterCallState::EndOfStream;
754:     }
755:     ENVOY_STREAM_LOG(trace, "decode data called: filter={} status={}", *this,
756:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
757:     if (state_.decoder_filter_chain_aborted_) {
758:       executeLocalReplyIfPrepared();
759:       ENVOY_STREAM_LOG(trace, "decodeData filter iteration aborted due to local reply: filter={}",
760:                        *this, (*entry)->filter_context_.config_name);
761:       return;
762:     }
763: 
764:     processNewlyAddedMetadata();
765: 
766:     if (!trailers_exists_at_start && filter_manager_callbacks_.requestTrailers() &&
767:         trailers_added_entry == decoder_filters_.end()) {
768:       end_stream = false;
769:       trailers_added_entry = entry;
770:     }
771: 
772:     // The decoder filter chain is finished here if the following is true:
773:     // 1. the last filter has observed the end_stream AND
774:     // 2. no filter, including the last filter, has injected trailers during header iteration.
775:     //    NOTE: end_stream is set to false above if a filter injected trailers.
776:     // If trailers were injected the end_stream will be processed in the `decodeTrailers()` method
777:     // below.
778:     terminal_filter_decoded_end_stream = end_stream && std::next(entry) == decoder_filters_.end();
779: 
780:     if (!(*entry)->commonHandleAfterDataCallback(status, data, state_.decoder_filters_streaming_) &&
781:         std::next(entry) != decoder_filters_.end()) {
782:       // Stop iteration IFF this is not the last filter. If it is the last filter, continue with
783:       // processing since we need to handle the case where a terminal filter wants to buffer, but
784:       // a previous filter has added trailers.
785:       break;
786:     }
787:   }
788: 
789:   // If trailers were adding during decodeData we need to trigger decodeTrailers in order
790:   // to allow filters to process the trailers.
791:   if (trailers_added_entry != decoder_filters_.end()) {
792:     decodeTrailers(trailers_added_entry->get(), *filter_manager_callbacks_.requestTrailers());
793:   }
794: 
795:   if (end_stream) {
796:     disarmRequestTimeout();
797:   }
798:   maybeEndDecode(terminal_filter_decoded_end_stream);
799: }
