880: void FilterManager::decodeMetadata(ActiveStreamDecoderFilter* filter, MetadataMap& metadata_map) {
881:   ScopeTrackerScopeState scope(&*this, dispatcher_);
882:   filter_manager_callbacks_.resetIdleTimer();
883: 
884:   // Filter iteration may start at the current filter.
885:   StreamDecoderFilters::Iterator entry =
886:       commonDecodePrefix(filter, FilterIterationStartState::CanStartFromCurrent);
887: 
888:   ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeMetadata));
889: 
890:   for (; entry != decoder_filters_.end(); entry++) {
891:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
892:     // If the filter pointed by entry has stopped for all frame type, stores metadata and returns.
893:     // If the filter pointed by entry hasn't returned from decodeHeaders, stores newly added
894:     // metadata in case decodeHeaders returns StopAllIteration. The latter can happen when headers
895:     // callbacks generate new metadata.
896:     if (!(*entry)->processed_headers_ || (*entry)->stoppedAll()) {
897:       Http::MetadataMapPtr metadata_map_ptr = std::make_unique<Http::MetadataMap>(metadata_map);
898:       (*entry)->getSavedRequestMetadata()->emplace_back(std::move(metadata_map_ptr));
899:       return;
900:     }
