1166: void ConnectionManagerImpl::ActiveStream::setResponseDecorator(ResponseHeaderMap& headers) {
1167:   ASSERT(active_span_ != nullptr);
1168: 
1169:   if (connection_manager_tracing_config_->operation_name_ == Tracing::OperationName::Ingress) {
1170:     // For ingress (inbound) responses, if the request headers do not include a
1171:     // decorator operation (override), and the decorated operation should be
1172:     // propagated, then pass the decorator's operation name (if defined)
1173:     // as a response header to enable the client service to use it in its client span.
1174:     if (state_.decorated_propagate_ && !state_.decorator_overriden_) {
1175:       absl::string_view decorated_operation =
1176:           route_decorator_ != nullptr ? route_decorator_->getOperation() : absl::string_view();
1177: 
1178:       if (!decorated_operation.empty()) {
1179:         // If the decorator operation is defined, set it as the response header.
1180:         headers.setEnvoyDecoratorOperation(decorated_operation);
1181:       }
1182:     }
1183:   } else if (connection_manager_tracing_config_->operation_name_ ==
1184:              Tracing::OperationName::Egress) {
1185:     const absl::string_view resp_operation_override = headers.getEnvoyDecoratorOperationValue();
1186: 
1187:     // For Egress (outbound) response, if a decorator operation name has been provided, it
1188:     // should be used to override the active span's operation.
1189:     if (!resp_operation_override.empty()) {
1190:       active_span_->setOperation(resp_operation_override);
1191:     }
1192:     // Remove header so not propagated to service.
