1078:     bool is_grpc_request, Code code, absl::string_view body,
1079:     const std::function<void(ResponseHeaderMap& headers)>& modify_headers, bool is_head_request,
1080:     const absl::optional<Grpc::Status::GrpcStatus> grpc_status, absl::string_view details) {
1081:   ENVOY_STREAM_LOG(debug, "Preparing local reply with details {}", *this, details);
1082:   ASSERT(!filter_manager_callbacks_.responseHeaders().has_value());
1083:   // For early error handling, do a best-effort attempt to create a filter chain
1084:   // to ensure access logging. If the filter chain already exists this will be
1085:   // a no-op.
1086:   createDownstreamFilterChain();
1087: 
1088:   if (prepared_local_reply_) {
1089:     return;
1090:   }
1091: 
1092:   prepared_local_reply_ = Utility::prepareLocalReply(
1093:       Utility::EncodeFunctions{
1094:           [this, modify_headers](ResponseHeaderMap& headers) -> void {
1095:             finalizeHeaders(filter_manager_callbacks_, streamInfo(), headers);
1096:             if (modify_headers) {
1097:               modify_headers(headers);
1098:             }
1099:           },
1100:           [this](ResponseHeaderMap& response_headers, Code& code, std::string& body,
1101:                  absl::string_view& content_type) -> void {
1102:             local_reply_.rewrite(filter_manager_callbacks_.requestHeaders().ptr(), response_headers,
1103:                                  streamInfo(), code, body, content_type);
1104:           },
1105:           [this](ResponseHeaderMapPtr&& headers, bool end_stream) -> void {
1106:             filter_manager_callbacks_.setResponseHeaders(std::move(headers));
1107:             encodeHeaders(nullptr, filter_manager_callbacks_.responseHeaders().ref(), end_stream);
1108:           },
1109:           [this](Buffer::Instance& data, bool end_stream) -> void {
1110:             encodeData(nullptr, data, end_stream,
1111:                        FilterManager::FilterIterationStartState::CanStartFromCurrent);
1112:           }},
1113:       Utility::LocalReplyData{is_grpc_request, code, body, grpc_status, is_head_request});
