1208: void FilterManager::encode1xxHeaders(ActiveStreamEncoderFilter* filter,
1209:                                      ResponseHeaderMap& headers) {
1210:   filter_manager_callbacks_.resetIdleTimer();
1211:   ASSERT(proxy_100_continue_);
1212:   // The caller must guarantee that encode1xxHeaders() is invoked at most once.
1213:   ASSERT(!state_.has_1xx_headers_ || filter != nullptr);
1214:   // Make sure commonContinue continues encode1xxHeaders.
1215:   state_.has_1xx_headers_ = true;
1216: 
1217:   // Similar to the block in encodeHeaders, run encode1xxHeaders on each
1218:   // filter. This is simpler than that case because 100 continue implies no
1219:   // end-stream, and because there are normal headers coming there's no need for
1220:   // complex continuation logic.
1221:   // 100-continue filter iteration should always start with the next filter if available.
1222:   StreamEncoderFilters::Iterator entry =
1223:       commonEncodePrefix(filter, false, FilterIterationStartState::AlwaysStartFromNext);
1224:   for (; entry != encoder_filters_.end(); entry++) {
1225:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
1226:     ASSERT(!(state_.filter_call_state_ & FilterCallState::Encode1xxHeaders));
1227:     state_.filter_call_state_ |= FilterCallState::Encode1xxHeaders;
1228:     const Filter1xxHeadersStatus status = (*entry)->handle_->encode1xxHeaders(headers);
1229:     state_.filter_call_state_ &= ~FilterCallState::Encode1xxHeaders;
1230: 
1231:     ENVOY_STREAM_LOG(trace, "encode 1xx continue headers called: filter={} status={}", *this,
1232:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
1233:     if (state_.encoder_filter_chain_aborted_) {
1234:       ENVOY_STREAM_LOG(trace,
1235:                        "encode1xxHeaders filter iteration aborted due to local reply: filter={}",
1236:                        *this, (*entry)->filter_context_.config_name);
1237:       return;
1238:     }
1239: 
1240:     if (!(*entry)->commonHandleAfter1xxHeadersCallback(status)) {
1241:       return;
1242:     }
1243:   }
1244: 
1245:   filter_manager_callbacks_.encode1xxHeaders(headers);
1246: }
