1267: 
1268:   // Headers filter iteration should always start with the next filter if available.
1269:   StreamEncoderFilters::Iterator entry =
1270:       commonEncodePrefix(filter, end_stream, FilterIterationStartState::AlwaysStartFromNext);
1271:   StreamEncoderFilters::Iterator continue_data_entry = encoder_filters_.end();
1272: 
1273:   for (; entry != encoder_filters_.end(); entry++) {
1274:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
1275:     ASSERT(!(state_.filter_call_state_ & FilterCallState::EncodeHeaders));
1276:     state_.filter_call_state_ |= FilterCallState::EncodeHeaders;
1277:     (*entry)->end_stream_ = (end_stream && continue_data_entry == encoder_filters_.end());
1278:     if ((*entry)->end_stream_) {
1279:       state_.filter_call_state_ |= FilterCallState::EndOfStream;
1280:     }
1281:     FilterHeadersStatus status = (*entry)->handle_->encodeHeaders(headers, (*entry)->end_stream_);
1282:     if (state_.encoder_filter_chain_aborted_) {
1283:       ENVOY_STREAM_LOG(trace,
1284:                        "encodeHeaders filter iteration aborted due to local reply: filter={}",
1285:                        *this, (*entry)->filter_context_.config_name);
1286:       status = FilterHeadersStatus::StopIteration;
1287:     }
1288: 
1289:     ASSERT(!(status == FilterHeadersStatus::ContinueAndDontEndStream && !(*entry)->end_stream_),
1290:            "Filters should not return FilterHeadersStatus::ContinueAndDontEndStream from "
1291:            "encodeHeaders when end_stream is already false");
1292: 
1293:     state_.filter_call_state_ &= ~FilterCallState::EncodeHeaders;
1294:     if ((*entry)->end_stream_) {
1295:       state_.filter_call_state_ &= ~FilterCallState::EndOfStream;
1296:     }
1297:     ENVOY_STREAM_LOG(trace, "encode headers called: filter={} status={}", *this,
1298:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status));
1299: 
1300:     (*entry)->processed_headers_ = true;
1301: 
1302:     const auto continue_iteration = (*entry)->commonHandleAfterHeadersCallback(status, end_stream);
1303: 
1304:     // If this filter ended the stream, encodeComplete() should be called for it.
1305:     if ((*entry)->end_stream_) {
1306:       (*entry)->handle_->encodeComplete();
1307:     }
1308: 
1309:     if (!continue_iteration) {
1310:       if (!(*entry)->end_stream_) {
