1323:   // Check if the filter chain above did not remove critical headers or set malformed header values.
1324:   // We could do this at the codec in order to prevent other places than the filter chain from
1325:   // removing critical headers, but it will come with the implementation complexity.
1326:   // See the previous attempt (#15658) for detail, and for now we choose to protect only against
1327:   // filter chains.
1328:   const auto status = HeaderUtility::checkRequiredResponseHeaders(headers);
1329:   if (!status.ok()) {
1330:     // If the check failed, then we reply with BadGateway, and stop the further processing.
1331:     sendLocalReply(
1332:         Http::Code::BadGateway, status.message(), nullptr, absl::nullopt,
1333:         absl::StrCat(StreamInfo::ResponseCodeDetails::get().FilterRemovedRequiredResponseHeaders,
1334:                      "{", StringUtil::replaceAllEmptySpace(status.message()), "}"));
1335:     return;
1336:   }
1337: 
1338:   const bool modified_end_stream = (end_stream && continue_data_entry == encoder_filters_.end());
1339:   state_.non_100_response_headers_encoded_ = true;
1340:   filter_manager_callbacks_.encodeHeaders(headers, modified_end_stream);
1341:   if (state_.saw_downstream_reset_) {
1342:     return;
1343:   }
1344:   maybeEndEncode(modified_end_stream);
1345: 
1346:   if (!modified_end_stream) {
1347:     maybeContinueEncoding(continue_data_entry);
