1572: void FilterManager::checkAndCloseStreamIfFullyClosed() {
1573:   ASSERT(filter_manager_callbacks_.isHalfCloseEnabled());
1574:   // When the independent half close is enabled the stream is always closed on error responses
1575:   // from the server.
1576:   if (filter_manager_callbacks_.responseHeaders().has_value()) {
1577:     const uint64_t response_status =
1578:         Http::Utility::getResponseStatus(filter_manager_callbacks_.responseHeaders().ref());
1579:     const bool error_response =
1580:         !(Http::CodeUtility::is2xx(response_status) || Http::CodeUtility::is1xx(response_status));
1581:     // Abort the decoder filter if it has not yet been completed.
1582:     if (error_response && !state_.decoder_filter_chain_complete_) {
1583:       state_.decoder_filter_chain_aborted_ = true;
1584:     }
1585:   }
1586: 
1587:   // Handle the case where the end_stream was received from both downstream client and upstream
1588:   // server but a decoder filter added either request body or trailers AND paused decoder filter
1589:   // chain iteration. This case is currently handled the same way as if independent half-close is
1590:   // disabled, i.e. proxying is stopped as soon as encoding has finished.
1591:   // TODO(yanavlasov): to support this case the codec needs to notify HCM that it has closed its low
1592:   // level stream
1593:   //                   to avoid use-after-free when HCM cleans-up its ActiveStream
1594:   const bool downstream_client_sent_end_stream = decoderObservedEndStream();
1595:   const bool decoder_filter_chain_paused =
1596:       !state_.decoder_filter_chain_complete_ && !state_.decoder_filter_chain_aborted_;
1597:   if (state_.encoder_filter_chain_complete_ && downstream_client_sent_end_stream &&
1598:       decoder_filter_chain_paused) {
1599:     state_.decoder_filter_chain_aborted_ = true;
1600:   }
1601: 
1602:   // If independent half close is enabled then close the stream when
1603:   // 1. Both encoder and decoder filter chains has completed.
1604:   // 2. Encoder filter chain has completed and decoder filter chain was aborted (i.e. local reply).
1605:   // There is no need to check for aborted encoder filter chain as the filter will either be
1606:   // completed or stream is reset.
1607:   if (state_.encoder_filter_chain_complete_ &&
1608:       (state_.decoder_filter_chain_complete_ || state_.decoder_filter_chain_aborted_)) {
1609:     ENVOY_STREAM_LOG(trace, "closing stream", *this);
1610:     filter_manager_callbacks_.endStream();
1611:   }
1612: }
