2137: void ConnectionManagerImpl::ActiveStream::onCodecEncodeComplete() {
2138:   ASSERT(!state_.codec_encode_complete_);
2139:   ENVOY_STREAM_LOG(debug, "Codec completed encoding stream.", *this);
2140:   state_.codec_encode_complete_ = true;
2141: 
2142:   // Update timing
2143:   filter_manager_.streamInfo().downstreamTiming().onLastDownstreamTxByteSent(
2144:       connection_manager_.time_source_);
2145:   request_response_timespan_->complete();
2146: 
2147:   // Only reap stream once.
2148:   if (state_.is_zombie_stream_) {
2149:     const bool skip_delay = shouldSkipDeferredCloseDelay();
2150:     connection_manager_.doDeferredStreamDestroy(*this);
2151:     // After destroying a zombie stream, check if the connection should be
2152:     // closed. doEndStream() call that created the zombie may have set
2153:     // drain_state_ to Closing, but checkForDeferredClose() couldn't close the
2154:     // connection at that time because streams_ wasn't empty yet.
2155:     if (connection_manager_.close_connection_on_zombie_stream_complete_) {
2156:       connection_manager_.checkForDeferredClose(skip_delay);
2157:     }
2158:   }
2159: }
