2187: void ConnectionManagerImpl::ActiveStream::modifySpan(Tracing::Span& span,
2188:                                                      bool upstream_span) const {
2189:   ASSERT(connection_manager_tracing_config_.has_value());
2190: 
2191:   const Tracing::HttpTraceContext trace_context(*request_headers_);
2192:   const Formatter::Context formatter_context{
2193:       request_headers_.get(), response_headers_.get(), response_trailers_.get(), {}, {},
2194:       active_span_.get()};
2195:   const Tracing::CustomTagContext ctx{trace_context, filter_manager_.streamInfo(),
2196:                                       formatter_context};
2197: 
2198:   // Cache the optional custom tags from the route first.
2199:   OptRef<const Tracing::CustomTagMap> route_custom_tags;
2200: 
2201:   if (route_tracing_ != nullptr) {
2202:     route_custom_tags.emplace(route_tracing_->getCustomTags());
2203:     for (const auto& tag : *route_custom_tags) {
2204:       tag.second->applySpan(span, ctx);
2205:     }
2206:   }
2207: 
2208:   for (const auto& tag : connection_manager_tracing_config_->custom_tags_) {
2209:     if (!route_custom_tags.has_value() || !route_custom_tags->contains(tag.first)) {
2210:       // If the tag is defined in both the connection manager and the route,
2211:       // use the route's tag.
2212:       tag.second->applySpan(span, ctx);
2213:     }
2214:   }
2215: 
2216:   // For same stream, there is only one downstream span. It's the active span.
2217:   // So we can determine whether the span is downstream span by comparing the
2218:   // span pointer.
2219:   const Formatter::Formatter* operation =
2220:       upstream_span
2221:           ? upstreamOperationNameFormatter(*connection_manager_tracing_config_, route_tracing_)
2222:           : operationNameFormatter(*connection_manager_tracing_config_, route_tracing_);
2223:   if (operation != nullptr) {
2224:     const auto op = operation->format(formatter_context, filter_manager_.streamInfo());
2225:     if (!op.empty()) {
2226:       span.setOperation(op);
2227:     }
2228:   }
2229: }
