2478: 
2479:   // This functionally deletes the stream (via deferred delete) so do not
2480:   // reference anything beyond this point.
2481:   // Make sure to not check for deferred close as we'll be immediately creating a new stream.
2482:   state_.is_internally_destroyed_ = true;
2483:   connection_manager_.doEndStream(*this, /*check_for_deferred_close*/ false);
2484: 
2485:   RequestDecoder& new_stream = connection_manager_.newStream(*response_encoder, true);
2486: 
2487:   // Set the new RequestDecoder on the ResponseEncoder. Even though all of the decoder callbacks
2488:   // have already been called at this point, the encoder still needs the new decoder for deferred
2489:   // logging in some cases.
2490:   // This doesn't currently work for HTTP/1 as the H/1 ResponseEncoder doesn't hold the active
2491:   // stream's pointer to the RequestDecoder.
2492:   response_encoder->setRequestDecoder(new_stream);
2493:   // We don't need to copy over the old parent FilterState from the old StreamInfo if it did not
2494:   // store any objects with a LifeSpan at or above DownstreamRequest. This is to avoid unnecessary
2495:   // heap allocation.
2496:   // TODO(snowp): In the case where connection level filter state has been set on the connection
2497:   // FilterState that we inherit, we'll end up copying this every time even though we could get
2498:   // away with just resetting it to the HCM filter_state_.
2499:   if (filter_state->hasDataAtOrAboveLifeSpan(StreamInfo::FilterState::LifeSpan::Request)) {
2500:     (*connection_manager_.streams_.begin())->filter_manager_.streamInfo().filter_state_ =
2501:         std::make_shared<StreamInfo::FilterStateImpl>(
2502:             filter_state->parent(), StreamInfo::FilterState::LifeSpan::FilterChain);
2503:   }
2504: 
2505:   // Make sure that relevant information makes it from the original stream info
2506:   // to the new one. Generally this should consist of all downstream related
2507:   // data, and not include upstream related data.
2508:   (*connection_manager_.streams_.begin())
2509:       ->filter_manager_.streamInfo()
2510:       .setFromForRecreateStream(filter_manager_.streamInfo());
